package arrays.praticando.aprendendo;import java.text.DecimalFormat;import java.util.Scanner;public class ArraysNoJava02 {    public static void main(String[] args) {        Scanner spaceInicial = new Scanner(System.in);        System.out.println("Qual é o espaço inicial? KM");        float espacoInicial =  spaceInicial.nextFloat();        Scanner inputVel = new Scanner(System.in);        System.out.println("Qual a velocidade Km/h");        float vel = inputVel.nextFloat();        Scanner inputTemp = new Scanner(System.in);        System.out.println("Qual o tempo? em horas: ");        float temp = inputTemp.nextFloat();        float espacoFinal = espacoInicial + (vel * temp);        String res = String.format("Em %.1f horas você percorrerá %.2f KM indo á %.2f Km/h", temp, espacoFinal, vel);        System.out.println(res);        float espacoInicialSi = (espacoFinal * 1000);        float velSi = (vel * 3.6f);        float tempSi = (temp * 120);        float espacoFinalNoSistemaInternacional = espacoInicialSi + (velSi * tempSi);        System.out.println("No sistema internacional ficaria: " +  espacoFinalNoSistemaInternacional + " metros que " +                "você percorreria indo a " + velSi + " m/s " + " em " + tempSi + " minutos ");    }}